"use client";

import { useEffect, useState } from "react";
import Link from "next/link";
import StepShell from "@/components/StepShell";
import { getRandomComplete } from "@/lib/learningMessages";
import { markStepDone } from "@/lib/progress";

// ===== 第一层：回顾内容（前 6 步关键操作） =====
const REVIEW_ITEMS = [
  { icon: "✋", step: "1", label: "摸一摸", text: "你翻折了纸张、推动了小车、转动了风车" },
  { icon: "⚖️", step: "2", label: "比一比", text: "你把 9 种运动分成了轴对称、平移、旋转三类" },
  { icon: "🔢", step: "3", label: "数一数", text: "长方形有 2 条对称轴，正方形有 4 条" },
  { icon: "✏️", step: "4", label: "画一画", text: "你画出了平移和旋转后的图形" },
  { icon: "🔄", step: "5", label: "变一变", text: "对折次数越多，剪出的图案越多——每次翻倍！" },
  { icon: "🏠", step: "6", label: "用一用", text: "你在公园、家里、学校都找到了运动现象" },
] as const;

const REVIEW_DURATION = 2800; // 每条 2.8 秒自动切换

// ===== 第二层：选择补充选项 =====
const CHOICE_OPTIONS = [
  { key: "A", text: "平移和旋转会改变图形的形状" },
  { key: "B", text: "轴对称图形对折后两边能完全重合" },
  { key: "C", text: "旋转一圈是 180 度" },
] as const;

type Layer = "review" | "express" | "verify" | "card";
type ExpressTab = "fill" | "draw" | "choose";

export default function DiscoverPage() {
  const [layer, setLayer] = useState<Layer>("review");
  const [completeMsg, setCompleteMsg] = useState("");
  useEffect(() => { setCompleteMsg(getRandomComplete()); }, []);

  // 完成卡片出现时标记 discover 步骤完成
  useEffect(() => {
    if (layer === "card") {
      markStepDone("motion", "discover");
    }
  }, [layer]);

  // ===== 第一层：回顾 =====
  const [reviewIdx, setReviewIdx] = useState(0);
  const reviewDone = reviewIdx >= REVIEW_ITEMS.length;

  useEffect(() => {
    if (layer !== "review") return;
    if (reviewIdx >= REVIEW_ITEMS.length) return;
    const id = setTimeout(() => setReviewIdx((p) => p + 1), REVIEW_DURATION);
    return () => clearTimeout(id);
  }, [layer, reviewIdx]);

  // ===== 第二层：表达发现 =====
  const [tab, setTab] = useState<ExpressTab>("fill");
  const [fillSymmetry, setFillSymmetry] = useState("");
  const [fillTranslation, setFillTranslation] = useState("");
  const [fillRotation, setFillRotation] = useState("");
  const [choice, setChoice] = useState<string | null>(null);
  const [customText, setCustomText] = useState("");

  const tabValid =
    tab === "fill"
      ? fillSymmetry !== "" && fillTranslation !== "" && fillRotation !== ""
      : tab === "draw"
        ? true
        : choice !== null && (choice !== "D" || customText.trim() !== "");

  const buildExpression = (): string => {
    if (tab === "fill")
      return `轴对称：${fillSymmetry}；平移：${fillTranslation}；旋转：${fillRotation}`;
    if (tab === "draw") return `我用画图表示了三种运动的区别`;
    if (choice === "D") return `我的发现：${customText.trim()}`;
    const opt = CHOICE_OPTIONS.find((o) => o.key === choice);
    return opt ? `我选 ${choice}：${opt.text}` : "";
  };

  // ===== 第三层：验证与命名 =====
  const [expression, setExpression] = useState("");
  const [verifyPhase, setVerifyPhase] = useState(0);
  // verifyPhase: 0=动画演示中, 1=命名揭示, 2=可进入发现卡

  const goVerify = () => {
    setExpression(buildExpression());
    setVerifyPhase(0);
    setLayer("verify");
  };

  useEffect(() => {
    if (layer !== "verify") return;
    if (verifyPhase !== 0) return;
    const t1 = setTimeout(() => setVerifyPhase(1), 2500);
    const t2 = setTimeout(() => setVerifyPhase(2), 5000);
    return () => {
      clearTimeout(t1);
      clearTimeout(t2);
    };
  }, [layer, verifyPhase]);

  const replay = () => {
    setLayer("review");
    setReviewIdx(0);
    setTab("fill");
    setFillSymmetry("");
    setFillTranslation("");
    setFillRotation("");
    setChoice(null);
    setCustomText("");
    setExpression("");
    setVerifyPhase(0);
  };

  return (
    <StepShell topicId="motion" stepId="discover">
      <div className="space-y-6">
        {/* ===== 第一层：回顾 ===== */}
        {layer === "review" && (
          <div className="space-y-6">
            <section className="animate-float-in rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
              <h2 className="text-center text-lg font-semibold text-[var(--text)]">
                我们一起走过的路
              </h2>
              <p className="mt-1 text-center text-sm text-[var(--text-secondary)]">
                回顾这 6 步，你做了好多事！
              </p>

              <div className="mt-6 flex min-h-[150px] items-center justify-center">
                {reviewIdx < REVIEW_ITEMS.length ? (
                  <div
                    key={reviewIdx}
                    className="animate-float-in flex flex-col items-center text-center"
                  >
                    <div className="text-5xl animate-bounce-soft">
                      {REVIEW_ITEMS[reviewIdx].icon}
                    </div>
                    <p className="mt-3 text-lg font-medium text-[var(--text)]">
                      {REVIEW_ITEMS[reviewIdx].step}.{" "}
                      {REVIEW_ITEMS[reviewIdx].label}
                    </p>
                    <p className="mt-1 text-[var(--text-secondary)]">
                      {REVIEW_ITEMS[reviewIdx].text}
                    </p>
                  </div>
                ) : (
                  <div className="animate-float-in flex flex-col items-center text-center">
                    <div className="text-4xl">🌟</div>
                    <p className="mt-2 text-lg font-semibold text-[var(--text)]">
                      6 步走完啦！
                    </p>
                  </div>
                )}
              </div>

              {/* 进度点 */}
              <div className="mt-4 flex justify-center gap-2">
                {REVIEW_ITEMS.map((it, i) => (
                  <div
                    key={it.step}
                    className={`h-2 w-2 rounded-full transition-colors ${
                      i < reviewIdx
                        ? "bg-[var(--primary)]"
                        : i === reviewIdx
                          ? "bg-[var(--accent)]"
                          : "bg-[var(--signal-pending)]"
                    }`}
                  />
                ))}
              </div>
            </section>

            {/* 三种运动总结桥接 */}
            {reviewDone && (
              <section className="animate-float-in rounded-[var(--radius)] border-2 border-[var(--signal-focus)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
                <p className="text-center text-sm font-medium text-[var(--text)]">
                  三种运动，三种特点
                </p>
                <div className="mt-5 grid grid-cols-3 gap-3">
                  <div className="text-center">
                    <div className="mx-auto flex h-14 w-14 items-center justify-center rounded-xl bg-[var(--primary)] text-2xl text-white shadow-sm">
                      📄
                    </div>
                    <p className="mt-2 text-sm font-bold text-[var(--text)]">轴对称</p>
                    <p className="text-xs text-[var(--text-muted)]">两边一样</p>
                  </div>
                  <div className="text-center">
                    <div className="mx-auto flex h-14 w-14 items-center justify-center rounded-xl bg-[var(--accent2)] text-2xl text-white shadow-sm">
                      →
                    </div>
                    <p className="mt-2 text-sm font-bold text-[var(--text)]">平移</p>
                    <p className="text-xs text-[var(--text-muted)]">直线移动</p>
                  </div>
                  <div className="text-center">
                    <div className="mx-auto flex h-14 w-14 items-center justify-center rounded-xl bg-[var(--accent)] text-2xl text-white shadow-sm">
                      🎡
                    </div>
                    <p className="mt-2 text-sm font-bold text-[var(--text)]">旋转</p>
                    <p className="text-xs text-[var(--text-muted)]">绕圈转动</p>
                  </div>
                </div>
                <div className="mt-6 text-center">
                  <button
                    onClick={() => setLayer("express")}
                    className="rounded-full bg-[var(--accent)] px-8 py-3 text-sm font-bold text-white shadow-[var(--shadow-accent)] transition-all hover:-translate-y-0.5 hover:shadow-[var(--shadow-md)]"
                  >
                    说说我的发现 →
                  </button>
                </div>
              </section>
            )}
          </div>
        )}

        {/* ===== 第二层：表达发现（三选一） ===== */}
        {layer === "express" && (
          <div className="space-y-6">
            <section className="animate-float-in rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-5 shadow-[var(--shadow-sm)]">
              <h2 className="text-center text-lg font-semibold text-[var(--text)]">
                你发现了什么？
              </h2>
              <p className="mt-1 text-center text-sm text-[var(--text-secondary)]">
                选一种你喜欢的方式表达出来（三选一）
              </p>
            </section>

            {/* 选项卡 */}
            <div className="flex justify-center gap-2">
              {(
                [
                  { key: "fill", icon: "🖊️", label: "填空描述" },
                  { key: "draw", icon: "🎨", label: "画图记录" },
                  { key: "choose", icon: "💬", label: "选择补充" },
                ] as { key: ExpressTab; icon: string; label: string }[]
              ).map((t) => (
                <button
                  key={t.key}
                  onClick={() => setTab(t.key)}
                  className={`rounded-full px-5 py-2 text-sm font-medium transition-all ${
                    tab === t.key
                      ? "bg-[var(--accent)] text-white shadow-[var(--shadow-accent)]"
                      : "bg-[var(--bg-soft)] text-[var(--text-secondary)] hover:bg-[var(--accent)]/30"
                  }`}
                >
                  {t.icon} {t.label}
                </button>
              ))}
            </div>

            {/* 填空描述 */}
            {tab === "fill" && (
              <section className="animate-float-in rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
                <div className="space-y-4">
                  <div className="flex items-center gap-3">
                    <span className="flex h-8 w-8 shrink-0 items-center justify-center rounded-lg bg-[var(--primary)] text-white">
                      📄
                    </span>
                    <span className="text-sm font-medium text-[var(--text)]">轴对称就是</span>
                    <input
                      type="text"
                      value={fillSymmetry}
                      onChange={(e) => setFillSymmetry(e.target.value)}
                      className="flex-1 rounded-lg border-2 border-[var(--border)] px-3 py-2 text-sm text-[var(--text)] focus:border-[var(--primary)] focus:outline-none"
                      placeholder="两边一样..."
                    />
                  </div>
                  <div className="flex items-center gap-3">
                    <span className="flex h-8 w-8 shrink-0 items-center justify-center rounded-lg bg-[var(--accent2)] text-white">
                      →
                    </span>
                    <span className="text-sm font-medium text-[var(--text)]">平移就是</span>
                    <input
                      type="text"
                      value={fillTranslation}
                      onChange={(e) => setFillTranslation(e.target.value)}
                      className="flex-1 rounded-lg border-2 border-[var(--border)] px-3 py-2 text-sm text-[var(--text)] focus:border-[var(--accent2)] focus:outline-none"
                      placeholder="直线移动..."
                    />
                  </div>
                  <div className="flex items-center gap-3">
                    <span className="flex h-8 w-8 shrink-0 items-center justify-center rounded-lg bg-[var(--accent)] text-white">
                      🎡
                    </span>
                    <span className="text-sm font-medium text-[var(--text)]">旋转就是</span>
                    <input
                      type="text"
                      value={fillRotation}
                      onChange={(e) => setFillRotation(e.target.value)}
                      className="flex-1 rounded-lg border-2 border-[var(--border)] px-3 py-2 text-sm text-[var(--text)] focus:border-[var(--accent)] focus:outline-none"
                      placeholder="绕圈转动..."
                    />
                  </div>
                </div>
                <p className="mt-4 text-center text-xs text-[var(--text-muted)]">
                  用你自己的话描述三种运动
                </p>
              </section>
            )}

            {/* 画图记录 - 交互式展示 */}
            {tab === "draw" && (
              <section className="animate-float-in rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
                <p className="text-center text-sm text-[var(--text-secondary)]">
                  下面这三幅图分别表示了三种运动
                </p>
                <div className="mt-5 grid grid-cols-3 gap-3">
                  <div className="text-center">
                    <div className="mx-auto flex h-20 w-20 items-center justify-center rounded-xl bg-[var(--primary)]/20">
                      <svg viewBox="0 0 60 60" className="h-14 w-14">
                        <path d="M 15 10 L 15 50 M 30 10 L 30 50 M 45 10 L 45 50" stroke="#38BDF8" strokeWidth="2" strokeDasharray="3 2" />
                        <path d="M 22 20 L 38 20 L 38 40 L 22 40 Z" fill="#38BDF8" opacity="0.5" />
                      </svg>
                    </div>
                    <p className="mt-2 text-xs font-bold text-[var(--text)]">轴对称</p>
                    <p className="text-[10px] text-[var(--text-muted)]">对折重合</p>
                  </div>
                  <div className="text-center">
                    <div className="mx-auto flex h-20 w-20 items-center justify-center rounded-xl bg-[var(--accent2)]/20">
                      <svg viewBox="0 0 60 60" className="h-14 w-14">
                        <rect x="10" y="25" width="15" height="12" fill="#34D399" opacity="0.5" />
                        <path d="M 28 31 L 38 31" stroke="#34D399" strokeWidth="2" strokeDasharray="3 2" />
                        <polygon points="38,28 45,31 38,34" fill="#34D399" />
                        <rect x="40" y="25" width="15" height="12" fill="#34D399" opacity="0.8" />
                      </svg>
                    </div>
                    <p className="mt-2 text-xs font-bold text-[var(--text)]">平移</p>
                    <p className="text-[10px] text-[var(--text-muted)]">位置变了</p>
                  </div>
                  <div className="text-center">
                    <div className="mx-auto flex h-20 w-20 items-center justify-center rounded-xl bg-[var(--accent)]/20">
                      <svg viewBox="0 0 60 60" className="h-14 w-14">
                        <circle cx="30" cy="30" r="15" fill="none" stroke="#FB7185" strokeWidth="2" strokeDasharray="3 2" />
                        <path d="M 30 30 L 30 15" stroke="#FB7185" strokeWidth="2" />
                        <circle cx="30" cy="30" r="3" fill="#FB7185" />
                        <path d="M 38 18 L 35 15 L 35 21 Z" fill="#FB7185" />
                      </svg>
                    </div>
                    <p className="mt-2 text-xs font-bold text-[var(--text)]">旋转</p>
                    <p className="text-[10px] text-[var(--text-muted)]">方向变了</p>
                  </div>
                </div>
                <p className="mt-4 text-center text-xs text-[var(--text-muted)]">
                  ✨ 画图已经帮你准备好了，直接进入下一步吧！
                </p>
              </section>
            )}

            {/* 选择 + 补充 */}
            {tab === "choose" && (
              <section className="animate-float-in rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
                <p className="text-center text-sm font-medium text-[var(--text)]">
                  哪个说法是正确的？
                </p>
                <div className="mt-4 space-y-3">
                  {CHOICE_OPTIONS.map((opt) => (
                    <button
                      key={opt.key}
                      onClick={() => setChoice(opt.key)}
                      className={`flex w-full items-center gap-3 rounded-lg border-2 px-4 py-3 text-left transition-all ${
                        choice === opt.key
                          ? "border-[var(--accent)] bg-[var(--accent)]/10"
                          : "border-[var(--border)] bg-[var(--bg-soft)] hover:border-[var(--accent)]/50"
                      }`}
                    >
                      <span className="flex h-7 w-7 shrink-0 items-center justify-center rounded-full bg-[var(--bg-card)] text-sm font-bold text-[var(--text)]">
                        {opt.key}
                      </span>
                      <span className="text-[var(--text)]">{opt.text}</span>
                    </button>
                  ))}

                  {/* D 其他 */}
                  <div
                    className={`flex items-center gap-3 rounded-lg border-2 px-4 py-3 transition-all ${
                      choice === "D"
                        ? "border-[var(--accent)] bg-[var(--accent)]/10"
                        : "border-[var(--border)] bg-[var(--bg-soft)]"
                    }`}
                  >
                    <button
                      onClick={() => setChoice("D")}
                      className="flex h-7 w-7 shrink-0 items-center justify-center rounded-full bg-[var(--bg-card)] text-sm font-bold text-[var(--text)]"
                      aria-label="选项 D"
                    >
                      D
                    </button>
                    <input
                      type="text"
                      value={customText}
                      onChange={(e) => {
                        setCustomText(e.target.value);
                        setChoice("D");
                      }}
                      placeholder="写下你自己的发现…"
                      className="flex-1 bg-transparent text-[var(--text)] placeholder:text-[var(--text-muted)] focus:outline-none"
                    />
                  </div>
                </div>
              </section>
            )}

            {/* 下一步 */}
            <div className="flex justify-center">
              <button
                onClick={goVerify}
                disabled={!tabValid}
                className="rounded-full bg-[var(--accent)] px-8 py-3 text-sm font-bold text-white shadow-[var(--shadow-accent)] transition-all hover:-translate-y-0.5 hover:shadow-[var(--shadow-md)] disabled:cursor-not-allowed disabled:opacity-40 disabled:hover:translate-y-0"
              >
                看看数学家怎么说 →
              </button>
            </div>
          </div>
        )}

        {/* ===== 第三层：验证与命名 ===== */}
        {layer === "verify" && (
          <div className="space-y-6">
            <section className="animate-float-in rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
              <h2 className="text-center text-lg font-semibold text-[var(--text)]">
                来验证一下你的发现
              </h2>
              <p className="mt-1 text-center text-sm text-[var(--text-secondary)]">
                三种运动的相同和不同
              </p>

              {/* 对比表格 */}
              <div className="mt-6 overflow-hidden rounded-xl border border-[var(--border)]">
                <table className="w-full text-sm">
                  <thead>
                    <tr className="bg-[var(--bg-soft)]">
                      <th className="px-3 py-3 text-left font-medium text-[var(--text-secondary)]">
                        运动
                      </th>
                      <th className="px-3 py-3 text-center font-medium text-[var(--text-secondary)]">
                        形状变吗？
                      </th>
                      <th className="px-3 py-3 text-center font-medium text-[var(--text-secondary)]">
                        大小变吗？
                      </th>
                      <th className="px-3 py-3 text-center font-medium text-[var(--text-secondary)]">
                        方向变吗？
                      </th>
                    </tr>
                  </thead>
                  <tbody>
                    <tr className="border-t border-[var(--border)]">
                      <td className="px-3 py-3 font-medium text-[var(--text)]">
                        📄 轴对称
                      </td>
                      <td className="px-3 py-3 text-center text-[var(--signal-success)]">
                        ✓ 不变
                      </td>
                      <td className="px-3 py-3 text-center text-[var(--signal-success)]">
                        ✓ 不变
                      </td>
                      <td className="px-3 py-3 text-center text-[var(--text-secondary)]">
                        对折
                      </td>
                    </tr>
                    <tr className="border-t border-[var(--border)]">
                      <td className="px-3 py-3 font-medium text-[var(--text)]">
                        → 平移
                      </td>
                      <td className="px-3 py-3 text-center text-[var(--signal-success)]">
                        ✓ 不变
                      </td>
                      <td className="px-3 py-3 text-center text-[var(--signal-success)]">
                        ✓ 不变
                      </td>
                      <td className="px-3 py-3 text-center text-[var(--signal-success)]">
                        ✓ 不变
                      </td>
                    </tr>
                    <tr className="border-t border-[var(--border)]">
                      <td className="px-3 py-3 font-medium text-[var(--text)]">
                        🎡 旋转
                      </td>
                      <td className="px-3 py-3 text-center text-[var(--signal-success)]">
                        ✓ 不变
                      </td>
                      <td className="px-3 py-3 text-center text-[var(--signal-success)]">
                        ✓ 不变
                      </td>
                      <td className="px-3 py-3 text-center text-[var(--accent)]">
                        ✗ 变了
                      </td>
                    </tr>
                  </tbody>
                </table>
              </div>
            </section>

            {/* 正式命名 */}
            {verifyPhase >= 1 && (
              <section className="animate-float-in rounded-[var(--radius)] border-2 border-[var(--signal-success)] bg-[var(--bg-card)] p-6 text-center shadow-[var(--shadow-md)]">
                <div className="text-4xl animate-bounce-soft">💡</div>
                <p className="mt-3 text-[var(--text)]">
                  数学家把这些运动叫做
                </p>
                <div className="mt-4 space-y-2">
                  <p className="text-xl font-bold text-[var(--primary)]">
                    轴对称图形 —— 对折后两边完全重合
                  </p>
                  <p className="text-xl font-bold text-[var(--accent2)]">
                    平移 —— 沿直线移动，形状大小都不变
                  </p>
                  <p className="text-xl font-bold text-[var(--accent)]">
                    旋转 —— 绕一个点转动，方向变了
                  </p>
                </div>
                <p className="mt-4 text-sm text-[var(--text-secondary)]">
                  它们都不改变图形的形状和大小！
                </p>
              </section>
            )}

            {verifyPhase >= 2 && (
              <div className="flex justify-center">
                <button
                  onClick={() => setLayer("card")}
                  className="animate-float-in rounded-full bg-[var(--accent)] px-8 py-3 text-sm font-bold text-white shadow-[var(--shadow-accent)] transition-all hover:-translate-y-0.5"
                >
                  生成我的发现卡 →
                </button>
              </div>
            )}
          </div>
        )}

        {/* ===== 我的运动发现卡 ===== */}
        {layer === "card" && (
          <div className="space-y-6">
            <section className="animate-float-in overflow-hidden rounded-[var(--radius)] bg-gradient-to-br from-[var(--primary)] to-[var(--accent)] p-1 shadow-[var(--shadow-lg)]">
              <div className="rounded-[var(--radius)] bg-[var(--bg-card)] p-6">
                {/* 卡头 */}
                <div className="flex items-center justify-between border-b border-dashed border-[var(--border)] pb-4">
                  <div className="flex items-center gap-2">
                    <span className="text-2xl">🌀</span>
                    <div>
                      <h3 className="text-lg font-bold text-[var(--text)]">
                        我的运动发现卡
                      </h3>
                      <p className="text-xs text-[var(--text-muted)]">
                        生活中的运动现象 · 七步探索
                      </p>
                    </div>
                  </div>
                  <span className="rounded-full bg-[var(--signal-success)] px-3 py-1 text-xs font-bold text-white">
                    完成
                  </span>
                </div>

                {/* 我的表达 */}
                <div className="mt-4">
                  <p className="text-xs font-medium text-[var(--text-muted)]">
                    我的发现
                  </p>
                  <p className="mt-1 rounded-lg bg-[var(--bg-soft)] px-4 py-3 text-[var(--text)]">
                    {expression || "（还没有填写）"}
                  </p>
                </div>

                {/* 三种运动总结 */}
                <div className="mt-4 grid grid-cols-3 gap-2">
                  <div
                    className="rounded-lg p-3 text-center"
                    style={{ backgroundColor: "var(--primary)" + "20" }}
                  >
                    <div className="text-xl">📄</div>
                    <p className="mt-1 text-xs font-bold text-[var(--text)]">轴对称</p>
                    <p className="text-[10px] text-[var(--text-muted)]">两边重合</p>
                  </div>
                  <div
                    className="rounded-lg p-3 text-center"
                    style={{ backgroundColor: "var(--accent2)" + "20" }}
                  >
                    <div className="text-xl">→</div>
                    <p className="mt-1 text-xs font-bold text-[var(--text)]">平移</p>
                    <p className="text-[10px] text-[var(--text-muted)]">直线移动</p>
                  </div>
                  <div
                    className="rounded-lg p-3 text-center"
                    style={{ backgroundColor: "var(--accent)" + "20" }}
                  >
                    <div className="text-xl">🎡</div>
                    <p className="mt-1 text-xs font-bold text-[var(--text)]">旋转</p>
                    <p className="text-[10px] text-[var(--text-muted)]">绕圈转动</p>
                  </div>
                </div>

                {/* 回顾六步 */}
                <div className="mt-4">
                  <p className="text-xs font-medium text-[var(--text-muted)]">
                    我走过的 6 步
                  </p>
                  <div className="mt-2 flex flex-wrap gap-2">
                    {REVIEW_ITEMS.map((it) => (
                      <span
                        key={it.step}
                        className="inline-flex items-center gap-1 rounded-full bg-[var(--bg-soft)] px-2.5 py-1 text-xs text-[var(--text-secondary)]"
                      >
                        <span>{it.icon}</span>
                        {it.label}
                      </span>
                    ))}
                  </div>
                </div>

                {/* 卡尾 */}
                <div className="mt-5 flex items-center justify-between border-t border-dashed border-[var(--border)] pt-4">
                  <span className="text-xs text-[var(--text-muted)]">
                    {completeMsg}
                  </span>
                  <span className="text-xs text-[var(--text-muted)]">
                    🌟 数学好好玩
                  </span>
                </div>
              </div>
            </section>

            <p className="text-center text-xs text-[var(--text-muted)]">
              💡 提示：可以截图保存这张卡片哦
            </p>

            <div className="flex flex-wrap items-center justify-center gap-3">
              <button
                onClick={replay}
                className="rounded-full border border-[var(--border)] bg-[var(--bg-soft)] px-5 py-2 text-sm font-medium text-[var(--text-secondary)] transition-colors hover:bg-[var(--bg-card)]"
              >
                再玩一次
              </button>
              <Link
                href="/learn/motion"
                className="rounded-full bg-[var(--primary)] px-5 py-2 text-sm font-bold text-white shadow-[var(--shadow-sm)] transition-all hover:-translate-y-0.5"
              >
                回到学习地图
              </Link>
              <Link
                href="/"
                className="rounded-full border border-[var(--border)] bg-[var(--bg-card)] px-5 py-2 text-sm font-medium text-[var(--text-secondary)] transition-colors hover:bg-[var(--bg-soft)]"
              >
                返回首页
              </Link>
            </div>
          </div>
        )}
      </div>
    </StepShell>
  );
}
